function Button({ children, variant = 'primary', size = 'md' }) {
  const base = 'inline-flex items-center justify-center rounded-lg font-medium transition-colors';

  const variants = {
    primary: 'bg-blue-600 text-white hover:bg-blue-700',
    secondary: 'bg-gray-100 text-gray-900 hover:bg-gray-200',
    danger: 'bg-red-600 text-white hover:bg-red-700',
    ghost: 'text-gray-600 hover:bg-gray-100',
  };

  const sizes = {
    sm: 'px-3 py-1.5 text-sm',
    md: 'px-4 py-2 text-sm',
    lg: 'px-6 py-3 text-base',
  };

  return (
    <button className={`${base} ${variants[variant]} ${sizes[size]}`}>
      {children}
    </button>
  );
}

// lib/utils.ts
import { clsx, type ClassValue } from 'clsx';
import { twMerge } from 'tailwind-merge';

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

// Uso no componente:
function Card({ className, children }) {
  return (
    <div className={cn(
      'rounded-lg border border-gray-200 bg-white p-4 shadow-sm',
      className  // classes externas sobrescrevem conflitos
    )}>
      {children}
    </div>
  );
}

// Quem usa pode customizar:
<Card className="p-8 shadow-lg">  {/* p-8 sobrescreve p-4 */}

import { cva } from 'class-variance-authority';

const buttonVariants = cva(
  // classes base (sempre aplicadas)
  'inline-flex items-center justify-center rounded-lg font-medium transition-colors',
  {
    variants: {
      variant: {
        primary: 'bg-blue-600 text-white hover:bg-blue-700',
        secondary: 'bg-gray-100 text-gray-900 hover:bg-gray-200',
        ghost: 'text-gray-600 hover:bg-gray-100',
      },
      size: {
        sm: 'px-3 py-1.5 text-sm',
        md: 'px-4 py-2 text-sm',
        lg: 'px-6 py-3 text-base',
      },
    },
    defaultVariants: {
      variant: 'primary',
      size: 'md',
    },
  }
);

// buttonVariants({ variant: 'secondary', size: 'lg' })
// → retorna a string de classes combinada

import { clsx } from 'clsx';

function Badge({ label, active }) {
  return (
    <span className={clsx(
      'rounded-full px-2 py-1 text-xs font-medium',
      active
        ? 'bg-green-100 text-green-800'
        : 'bg-gray-100 text-gray-600'
    )}>
      {label}
    </span>
  );
}

