challenge.solution:
function Badge({ label, variant = 'info' }) {
  const variants = {
    success: 'bg-green-100 text-green-800',
    warning: 'bg-yellow-100 text-yellow-800',
    error: 'bg-red-100 text-red-800',
    info: 'bg-blue-100 text-blue-800',
  };

  return (
    <span className={`rounded-full px-3 py-1 text-xs font-medium ${variants[variant]}`}>
      {label}
    </span>
  );
}

export default function App() {
  return (
    <div className="flex gap-2 p-8">
      <Badge label="Ativo" variant="success" />
      <Badge label="Pendente" variant="warning" />
      <Badge label="Erro" variant="error" />
      <Badge label="Info" variant="info" />
    </div>
  );
}
